const body = items[0].json.body;
const DEFAULT_LAT = 32.3182;  // Cedar Creek Lake
const DEFAULT_LONG = -96.0553;

let lat = body.userLocation?.lat || body.lat || DEFAULT_LAT;
let long = body.userLocation?.long || body.long || DEFAULT_LONG;

return {
  json: {
    ...body,
    userLocation: { lat, long },
    lat,
    long
  }
};
